import React from 'react';
import './GridItem.css';

export default function GridItem(props) {
    return (
    <div className="grid-item">
        { props.children }
        <div className="break"></div>
        <button className="pop-up-button" onClick={() => props.setTrigger(true)}>open</button>
    </div>
    );
}
